def categorize_email(email: dict) -> str:
    score = 0.0

    # VIP sender check
    if email["from"] in email["vip_allowlist"]:
        score += 0.5

    # Keyword match in subject
    subject_lower = email["subject"].lower()
    for word in email["urgent_words"]:
        if word.lower() in subject_lower:
            score += 0.3
            break

    # Reply window check
    if email["hours_unread"] >= 24:
        score += 0.2

    # Routing thresholds
    if score >= 0.7:
        return "critical"
    elif score >= 0.4:
        return "warn"
    else:
        return "info"
